CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TYPE profile_type AS ENUM ('PERSONAL','FAMILY','BUSINESS');
CREATE TYPE category_type AS ENUM ('INCOME','FIXED_EXPENSE','VARIABLE_EXPENSE','SAVING','DEBT','INVESTMENT');
CREATE TYPE movement_type AS ENUM ('INCOME','EXPENSE','SAVING','TRANSFER','ADJUSTMENT');
CREATE TYPE movement_origin AS ENUM ('MANUAL','IMPORT','RECURRENT','SYSTEM');
CREATE TYPE movement_status AS ENUM ('CONFIRMED','PENDING','IGNORED');
CREATE TABLE app_user(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),email VARCHAR(120) UNIQUE NOT NULL,password_hash VARCHAR(255) NOT NULL,full_name VARCHAR(120) NOT NULL,created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE financial_profile(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),user_id UUID NOT NULL REFERENCES app_user(id),name VARCHAR(100) NOT NULL,type profile_type NOT NULL,base_currency CHAR(3) NOT NULL,active_year INT NOT NULL);
CREATE TABLE account(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),name VARCHAR(120) NOT NULL,account_type VARCHAR(40) NOT NULL,currency CHAR(3) NOT NULL,credit_limit NUMERIC(19,2),statement_close_day INT,due_day INT,active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE payment_method(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),account_id UUID REFERENCES account(id),name VARCHAR(80) NOT NULL,method_type VARCHAR(40) NOT NULL);
CREATE TABLE category(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID REFERENCES financial_profile(id),parent_id UUID REFERENCES category(id),name VARCHAR(120) NOT NULL,type category_type NOT NULL,scope profile_type,recommended_budget NUMERIC(19,2),active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE tag(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),name VARCHAR(50) NOT NULL);
CREATE TABLE transaction(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),account_id UUID NOT NULL REFERENCES account(id),payment_method_id UUID REFERENCES payment_method(id),category_id UUID REFERENCES category(id),movement_type movement_type NOT NULL,real_date DATE NOT NULL,budget_date DATE NOT NULL,amount NUMERIC(19,2) NOT NULL,currency CHAR(3) NOT NULL,description VARCHAR(255),origin movement_origin NOT NULL,status movement_status NOT NULL DEFAULT 'CONFIRMED');
CREATE TABLE transaction_tag(transaction_id UUID REFERENCES transaction(id),tag_id UUID REFERENCES tag(id),PRIMARY KEY(transaction_id,tag_id));
CREATE TABLE budget_year(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),year INT NOT NULL,target_income NUMERIC(19,2),target_saving NUMERIC(19,2),UNIQUE(profile_id,year));
CREATE TABLE budget_month(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),budget_year_id UUID NOT NULL REFERENCES budget_year(id),month SMALLINT NOT NULL CHECK (month between 1 and 12),UNIQUE(budget_year_id,month));
CREATE TABLE budget_category_item(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),budget_month_id UUID NOT NULL REFERENCES budget_month(id),category_id UUID NOT NULL REFERENCES category(id),budget_amount NUMERIC(19,2) NOT NULL,real_amount NUMERIC(19,2) NOT NULL DEFAULT 0);
CREATE TABLE financial_goal(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),name VARCHAR(120) NOT NULL,target_amount NUMERIC(19,2) NOT NULL,accumulated_amount NUMERIC(19,2) NOT NULL DEFAULT 0,target_date DATE,status VARCHAR(30) NOT NULL);
CREATE TABLE goal_contribution(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),goal_id UUID NOT NULL REFERENCES financial_goal(id),transaction_id UUID REFERENCES transaction(id),amount NUMERIC(19,2) NOT NULL,contribution_date DATE NOT NULL);
CREATE TABLE credit_card_statement(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),account_id UUID NOT NULL REFERENCES account(id),period_year INT NOT NULL,period_month INT NOT NULL,total_amount NUMERIC(19,2) NOT NULL,min_payment NUMERIC(19,2) NOT NULL,due_date DATE NOT NULL);
CREATE TABLE credit_card_installment(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),statement_id UUID NOT NULL REFERENCES credit_card_statement(id),description VARCHAR(255),total_installments INT NOT NULL,current_installment INT NOT NULL,amount NUMERIC(19,2) NOT NULL,remaining_amount NUMERIC(19,2) NOT NULL);
CREATE TABLE inflation_index(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID REFERENCES financial_profile(id),year INT NOT NULL,month INT NOT NULL,index_value NUMERIC(8,4) NOT NULL,source VARCHAR(20) NOT NULL,UNIQUE(profile_id,year,month,source));
CREATE TABLE habit(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),name VARCHAR(120) NOT NULL,frequency VARCHAR(20) NOT NULL,area VARCHAR(20) NOT NULL,active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE habit_checkin(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),habit_id UUID NOT NULL REFERENCES habit(id),checkin_date DATE NOT NULL,completed BOOLEAN NOT NULL);
CREATE TABLE import_batch(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),file_name VARCHAR(180) NOT NULL,file_type VARCHAR(10) NOT NULL,status VARCHAR(20) NOT NULL,created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE import_row(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),batch_id UUID NOT NULL REFERENCES import_batch(id),row_number INT NOT NULL,payload JSONB NOT NULL,duplicate_flag BOOLEAN NOT NULL DEFAULT FALSE,resolved_transaction_id UUID REFERENCES transaction(id));
CREATE TABLE categorization_rule(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),profile_id UUID NOT NULL REFERENCES financial_profile(id),keyword VARCHAR(80) NOT NULL,category_id UUID NOT NULL REFERENCES category(id),priority INT NOT NULL DEFAULT 100,active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE audit_log(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),user_id UUID REFERENCES app_user(id),profile_id UUID REFERENCES financial_profile(id),entity_name VARCHAR(80) NOT NULL,entity_id UUID,action VARCHAR(20) NOT NULL,payload JSONB,created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE INDEX idx_tx_profile_budget_date ON transaction(profile_id,budget_date);
CREATE INDEX idx_tx_profile_category ON transaction(profile_id,category_id);
CREATE INDEX idx_tx_profile_account ON transaction(profile_id,account_id);
CREATE INDEX idx_budget_month_year ON budget_month(budget_year_id,month);
